const data = $input.first().json;
const files = data.files || [];
const spreadsheetId = files.length > 0 ? files[0].id : null;
if (!spreadsheetId) throw new Error(`スプレッドシートが見つかりません: ${data.fileName}`);

const MULTI_PERSON = ['梶原通信', 'LLS電気', '株式会社トラストテクノス', '株式会社RISE'];
const isMulti = MULTI_PERSON.includes(data.employeeName);

const results = [];
for (const site of (data.sites || [])) {
  const row = {
    spreadsheetId,
    employeeName: data.employeeName,
    replyToken: data.replyToken,
    parsedDate: data.parsedDate,
    fileName: data.fileName,
    hasBilling: data.hasBilling || false,
    billingSites: data.billingSites || [],
    billingFileName: data.billingFileName || '',
    '日付': data.parsedDate,
    '区分': site.kubun || '',
    '会社名': site.companyName || '',
    '物件名': site.propertyName || '',
    '開始時刻': site.startTime || '',
    '終了時刻': site.endTime || '',
    '休憩(分)': site.breakMinutes || 0,
    '稼働時間': site.workHours || '',
    '作業内容': site.workContent || '',
    '高速料金': site.highwayFee || 0,
    '距離(km)': site.distance || 0,
    '駐車場': site.parkingFee || 0,
    '資材費': site.materialCost || 0
  };
  if (isMulti) {
    row['人員数'] = site.staffCount || 0;
    row['人員名'] = site.staffNames || '';
  }
  results.push({ json: row });
}
if (results.length === 0) throw new Error('書き込むデータがありません');
return results;

