const data = $input.first().json;

const normalize = (name) =>
  (name || '').replace(/株式会社|有限会社|合同会社|一般社団法人|一般財団法人/g, '').trim();

const BILLING_COMPANIES = [
  '港振興業', 'トラストテクノス', '平成システム', 'FGE',
  'mtr', 'オークコミュニケーション', 'ライズ',
  '千里スカイハイツ管理組合', '菊次', 'ページ', 'G-STYLE', '梶原通信'
];
const CLOSING_20 = ['平成システム', '梶原通信'];
const COMPANY_ALIASES = {
  '平成': '平成システム', 'トラスト': 'トラストテクノス',
  'オーク': 'オークコミュニケーション', '千里': '千里スカイハイツ管理組合',
  '港': '港振興業', '港振': '港振興業', 'コウシン': '港振興業',
  '梶原': '梶原通信', 'ジースタイル': 'G-STYLE', 'Gスタイル': 'G-STYLE'
};

const resolveAlias = (name) => {
  for (const [alias, full] of Object.entries(COMPANY_ALIASES)) {
    if (normalize(name).includes(normalize(alias))) return full;
  }
  return name;
};

const parts = (data.parsedDate || '').split('/');
const year  = parseInt(parts[0]) || 0;
const month = parseInt(parts[1]) || 0;
const day   = parseInt(parts[2]) || 0;

const billingSites = (data.sites || []).filter(site => {
  const resolved = resolveAlias(site.companyName);
  const norm = normalize(resolved);
  return BILLING_COMPANIES.some(c => norm.includes(normalize(c)) || normalize(c).includes(norm));
});

if (billingSites.length === 0) {
  return [{ json: { ...data, hasBilling: false } }];
}

const groups = {};
for (const site of billingSites) {
  const resolved = resolveAlias(site.companyName);
  const norm = normalize(resolved);
  const is20 = CLOSING_20.some(c => norm.includes(normalize(c)) || normalize(c).includes(norm));
  let bYear = year, bMonth = month;
  if (is20 && day >= 21) {
    bMonth = month + 1;
    if (bMonth > 12) { bMonth = 1; bYear = year + 1; }
  }
  const key = `${bYear}-${bMonth}`;
  if (!groups[key]) groups[key] = { bYear, bMonth, sites: [] };
  groups[key].sites.push({ ...site, companyName: resolved });
}

const results = [];
for (const group of Object.values(groups)) {
  const billingFileName = `請求集計_${group.bYear}年${String(group.bMonth).padStart(2,'0')}月`;
  results.push({ json: { ...data, billingYear: group.bYear, billingMonth: group.bMonth, billingFileName, billingSites: group.sites, hasBilling: true } });
}
return results;

